// 成績管理 / 通知表 — ドメインモデルとモックデータ
// 中学・高校の担任 / 教科担当が、1クラスの成績を教科横断で確認・評定し、
// 基準未達（赤点・要観察）の生徒を把握するための画面。

export const PASSING_SCORE = 30 // 合格基準点（これ未満は赤点）

// 5教科
export const SUBJECTS = [
  { id: "kokugo", name: "国語", short: "国" },
  { id: "sugaku", name: "数学", short: "数" },
  { id: "eigo", name: "英語", short: "英" },
  { id: "rika", name: "理科", short: "理" },
  { id: "shakai", name: "社会", short: "社" },
] as const

export type SubjectId = (typeof SUBJECTS)[number]["id"]

// 観点別評価の3観点（指導要録準拠）
export const VIEWPOINTS = [
  { id: "knowledge", name: "知識・技能", short: "知技" },
  { id: "thinking", name: "思考・判断・表現", short: "思判表" },
  { id: "attitude", name: "主体的に取り組む態度", short: "態度" },
] as const

export type ViewpointId = (typeof VIEWPOINTS)[number]["id"]
export type ViewpointGrade = "A" | "B" | "C"

// 評定は1〜5の5段階
export type Hyotei = 1 | 2 | 3 | 4 | 5

export interface SubjectResult {
  /** 100点満点の素点。未入力は null。 */
  score: number | null
  /** 観点別評価 A/B/C。 */
  viewpoints: Record<ViewpointId, ViewpointGrade>
  /** 評定 1〜5（観点から自動算出だが、教科担当が上書き確定できる）。 */
  hyotei: Hyotei | null
  /** 確定済みか（確定すると通知表に反映・ロック）。 */
  confirmed: boolean
}

export interface Student {
  id: string
  no: number // 出席番号
  name: string
  kana: string
  results: Record<SubjectId, SubjectResult>
}

function vp(k: ViewpointGrade, t: ViewpointGrade, a: ViewpointGrade): Record<ViewpointId, ViewpointGrade> {
  return { knowledge: k, thinking: t, attitude: a }
}

// 観点（A=3/B=2/C=1）の合計から評定を機械的に提案する。
// 9点満点 → 5:8-9 / 4:6-7 / 3:4-5 / 2:2-3 / 1:0-1
const VP_POINT: Record<ViewpointGrade, number> = { A: 3, B: 2, C: 1 }
export function suggestHyotei(viewpoints: Record<ViewpointId, ViewpointGrade>): Hyotei {
  const total = VIEWPOINTS.reduce((sum, v) => sum + VP_POINT[viewpoints[v.id]], 0)
  if (total >= 8) return 5
  if (total >= 6) return 4
  if (total >= 4) return 3
  if (total >= 2) return 2
  return 1
}

function r(
  score: number | null,
  k: ViewpointGrade,
  t: ViewpointGrade,
  a: ViewpointGrade,
  confirmed = false
): SubjectResult {
  const viewpoints = vp(k, t, a)
  return { score, viewpoints, hyotei: suggestHyotei(viewpoints), confirmed }
}

