// ── 判定・集計ロジック ──────────────────────────────────

export type ScoreStatus = "passing" | "watch" | "failing" | "unentered"

/** 1教科の平均点（未入力は母数から除外）。 */
export function subjectAverage(students: Student[], subject: SubjectId): number {
  const scores = students.map((s) => s.results[subject].score).filter((v): v is number => v != null)
  if (scores.length === 0) return 0
  return Math.round((scores.reduce((a, b) => a + b, 0) / scores.length) * 10) / 10
}

export interface SubjectStats {
  average: number
  max: number
  min: number
  count: number // 採点済み人数
  failing: number // 赤点人数
}

export function subjectStats(students: Student[], subject: SubjectId): SubjectStats {
  const scores = students.map((s) => s.results[subject].score).filter((v): v is number => v != null)
  const average = subjectAverage(students, subject)
  return {
    average,
    max: scores.length ? Math.max(...scores) : 0,
    min: scores.length ? Math.min(...scores) : 0,
    count: scores.length,
    failing: scores.filter((v) => v < PASSING_SCORE).length,
  }
}

/** 素点を「合格基準点」と「クラス平均」に照らして状態判定する。 */
export function scoreStatus(score: number | null, classAverage: number): ScoreStatus {
  if (score == null) return "unentered"
  if (score < PASSING_SCORE) return "failing" // 赤点
  if (score < classAverage) return "watch" // 要観察（平均未満）
  return "passing"
}

/** 1人の生徒が赤点を抱える教科数。 */
export function failingCount(student: Student): number {
  return SUBJECTS.reduce((n, s) => {
    const sc = student.results[s.id].score
    return n + (sc != null && sc < PASSING_SCORE ? 1 : 0)
  }, 0)
}

/** 成績分布（バンドごとの人数）。0-29 が赤点ゾーン。 */
export const SCORE_BANDS = [
  { id: "f", label: "0–29（赤点）", min: 0, max: 29, tone: "destructive" as const },
  { id: "d", label: "30–49", min: 30, max: 49, tone: "warning" as const },
  { id: "c", label: "50–69", min: 50, max: 69, tone: "info" as const },
  { id: "b", label: "70–89", min: 70, max: 89, tone: "primary" as const },
  { id: "a", label: "90–100", min: 90, max: 100, tone: "success" as const },
]

export function scoreDistribution(students: Student[], subject: SubjectId) {
  return SCORE_BANDS.map((band) => ({
    ...band,
    count: students.filter((s) => {
      const sc = s.results[subject].score
      return sc != null && sc >= band.min && sc <= band.max
    }).length,
  }))
}

export const CLASS_LABEL = "2年3組"
export const TERM_LABEL = "2026年度 1学期 期末"

"use client"

import * as React from "react"
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  DistributionBar,
  Meter,
  ReferenceValue,
  Select,
  Statistic,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetTitle,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@gunjo/ui"
import {
  IconAlertTriangle,
  IconLock,
  IconEye,
  IconCheck,
  IconPencil,
} from "@tabler/icons-react"

import {
  CLASS_LABEL,
  TERM_LABEL,
  PASSING_SCORE,
  SUBJECTS,
  VIEWPOINTS,
  STUDENTS,
  type Student,
  type SubjectId,
  type Hyotei,
  type ViewpointGrade,
  type ViewpointId,
  type ScoreStatus,
  suggestHyotei,
  subjectStats,
  subjectAverage,
  scoreStatus,
  failingCount,
  scoreDistribution,
} from "./data"

// 評定セルで使う「点数 vs 基準」のレンジ。
// ReferenceValue は本来 "高い=異常" の医療系プリミティブだが、
// 成績では「低い=赤点」。criticalLow=合格基準点、low=クラス平均 を渡すと
// criticalLow以下→destructive(赤点)、low未満→warning(要観察) に化けてくれる。
function gradeRange(classAverage: number) {
  return { criticalLow: PASSING_SCORE - 1, low: classAverage }
}

const STATUS_BADGE: Record<
  Exclude<ScoreStatus, "passing" | "unentered">,
  { variant: "destructive" | "warning"; label: string }
> = {
  failing: { variant: "destructive", label: "赤点" },
  watch: { variant: "warning", label: "要観察" },
}

const VP_BADGE: Record<ViewpointGrade, "success" | "info" | "warning"> = {
  A: "success",
  B: "info",
  C: "warning",
}

function ViewpointBadge({ grade }: { grade: ViewpointGrade }) {
  return (
    <Badge variant={VP_BADGE[grade]} className="w-6 justify-center px-0">
      {grade}
    </Badge>
  )
}

export default function GradebookScreen() {
  const [students, setStudents] = React.useState<Student[]>(STUDENTS)
  const [focusSubject, setFocusSubject] = React.useState<SubjectId>("sugaku")
  const [editing, setEditing] = React.useState<{ studentId: string; subject: SubjectId } | null>(null)
  const [reportStudentId, setReportStudentId] = React.useState<string | null>(null)

  // 教科ごとの平均（要観察判定の基準）。生徒データが変わると再計算。
  const averages = React.useMemo(() => {
    const m = {} as Record<SubjectId, number>
    for (const s of SUBJECTS) m[s.id] = subjectAverage(students, s.id)
    return m
  }, [students])

  const focusStats = React.useMemo(() => subjectStats(students, focusSubject), [students, focusSubject])
  const distribution = React.useMemo(() => scoreDistribution(students, focusSubject), [students, focusSubject])

  const editingStudent = editing ? students.find((s) => s.id === editing.studentId) ?? null : null
  const reportStudent = reportStudentId ? students.find((s) => s.id === reportStudentId) ?? null : null

  const classFailing = students.filter((s) => failingCount(s) > 0).length

  function updateResult(
    studentId: string,
    subject: SubjectId,
    patch: Partial<Student["results"][SubjectId]>
  ) {
    setStudents((prev) =>
      prev.map((s) =>
        s.id === studentId
          ? { ...s, results: { ...s.results, [subject]: { ...s.results[subject], ...patch } } }
          : s
      )
    )
  }

  return (
    <div className="mx-auto w-full max-w-7xl space-y-6 px-4 py-6 sm:px-6">
      {/* ── ヘッダ ── */}
      <header className="space-y-3">
        <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
          <span>{CLASS_LABEL}</span>
          <span aria-hidden>·</span>
          <span>{TERM_LABEL}</span>
        </div>
        <h1 className="text-2xl font-bold tracking-tight">成績管理 / 通知表</h1>
        <p className="max-w-2xl text-sm text-muted-foreground">
          クラスの成績を教科横断で確認し、評定の入力・確定を行います。
          合格基準点（{PASSING_SCORE}点）未満は<strong className="text-destructive">赤点</strong>、
          クラス平均未満は<strong className="text-warning">要観察</strong>として、色だけに頼らず記号・ラベルでも示します。
        </p>
      </header>

      {/* ── クラス全体サマリ（要観察生徒の早見） ── */}
      <section aria-labelledby="class-summary-heading" className="space-y-3">
        <h2 id="class-summary-heading" className="sr-only">
          クラス全体の概況
        </h2>
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
          <Statistic label="在籍" value={`${students.length}名`} hint="2年3組" />
          <Statistic
            label="赤点を含む生徒"
            value={`${classFailing}名`}
            trend={classFailing > 0 ? "down" : "flat"}
            tone={classFailing > 0 ? "negative" : "neutral"}
            hint={`1教科でも${PASSING_SCORE}点未満`}
          />
          <Statistic
            label={`${SUBJECTS.find((s) => s.id === focusSubject)?.name} 平均`}
            value={`${focusStats.average}点`}
            hint={`最高 ${focusStats.max} / 最低 ${focusStats.min}`}
          />
          <Statistic
            label={`${SUBJECTS.find((s) => s.id === focusSubject)?.name} 赤点`}
            value={`${focusStats.failing}名`}
            trend={focusStats.failing > 0 ? "down" : "flat"}
            tone={focusStats.failing > 0 ? "negative" : "neutral"}
            hint={`採点済み ${focusStats.count}名`}
          />
        </div>
      </section>

      {/* ── 成績一覧マトリクス（生徒 × 教科） ── */}
      <section aria-labelledby="matrix-heading" className="space-y-3">
        <div className="flex flex-wrap items-end justify-between gap-3">
          <div>
            <h2 id="matrix-heading" className="text-lg font-semibold">
              成績一覧マトリクス
            </h2>
            <p className="text-sm text-muted-foreground">
              行＝生徒、列＝教科。各セルは素点と判定。行をクリックすると個人通知表を表示します。
            </p>
          </div>
          <ul className="flex flex-wrap items-center gap-2 text-xs" aria-label="凡例">
            <li>
              <Badge variant="destructive">赤点</Badge>
              <span className="ml-1 text-muted-foreground">{PASSING_SCORE}点未満</span>
            </li>
            <li>
              <Badge variant="warning">要観察</Badge>
              <span className="ml-1 text-muted-foreground">平均未満</span>
            </li>
          </ul>
        </div>

        {/* role="grid" ではなくネイティブの table セマンティクスで二軸ヘッダを表現。
            横スクロール時も先頭列（生徒名）を sticky で固定。 */}
        <div className="overflow-x-auto rounded-lg border bg-card">
          <table className="w-full min-w-[760px] caption-bottom border-collapse text-sm">
            <caption className="border-t px-3 py-2 text-left text-xs text-muted-foreground">
              {CLASS_LABEL} 成績一覧（{TERM_LABEL}）。各教科セルの「赤点」「要観察」はラベルと記号でも表示しています。
            </caption>
            <thead>
              <tr className="border-b bg-accent/55">
                <th
                  scope="col"
                  className="sticky left-0 z-10 h-11 bg-accent/55 px-3 text-left align-middle text-xs font-semibold text-muted-foreground"
                >
                  生徒
                </th>
                {SUBJECTS.map((subj) => (
                  <th
                    key={subj.id}
                    scope="col"
                    className="h-11 px-3 text-center align-middle text-xs font-semibold text-muted-foreground"
                  >
                    <button
                      type="button"
                      onClick={() => setFocusSubject(subj.id)}
                      aria-pressed={focusSubject === subj.id}
                      className="mx-auto inline-flex flex-col items-center gap-0.5 rounded px-2 py-1 hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring aria-pressed:bg-background aria-pressed:text-foreground aria-pressed:shadow-sm"
                    >
                      <span>{subj.name}</span>
                      <span className="text-[10px] font-normal text-muted-foreground">
                        平均 {averages[subj.id]}
                      </span>
                    </button>
                  </th>
                ))}
                <th scope="col" className="h-11 px-3 text-center align-middle text-xs font-semibold text-muted-foreground">
                  赤点数
                </th>
              </tr>
            </thead>
            <tbody>
              {students.map((student) => {
                const nFail = failingCount(student)
                return (
                  <tr
                    key={student.id}
                    className="border-b transition-colors hover:bg-muted/40 focus-within:bg-muted/40"
                  >
                    <th
                      scope="row"
                      className="sticky left-0 z-10 bg-card px-3 py-2 text-left align-middle font-normal"
                    >
                      <button
                        type="button"
                        onClick={() => setReportStudentId(student.id)}
                        className="group flex flex-col items-start rounded text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                      >
                        <span className="flex items-center gap-1.5 font-medium group-hover:underline">
                          {student.no}. {student.name}
                          {nFail > 0 && (
                            <IconAlertTriangle className="h-3.5 w-3.5 text-destructive" aria-hidden />
                          )}
                        </span>
                        <span className="text-[11px] text-muted-foreground">{student.kana}</span>
                      </button>
                    </th>
                    {SUBJECTS.map((subj) => {
                      const result = student.results[subj.id]
                      const status = scoreStatus(result.score, averages[subj.id])
                      const cellBg =
                        status === "failing"
                          ? "bg-destructive-subtle/40"
                          : status === "watch"
                            ? "bg-warning-subtle/30"
                            : undefined
                      return (
                        <td
                          key={subj.id}
                          className={`px-3 py-2 text-center align-middle ${cellBg ?? ""}`}
                        >
                          <div className="flex flex-col items-center gap-1">
                            {result.score == null ? (
                              <span className="text-xs text-muted-foreground">未入力</span>
                            ) : (
                              <ReferenceValue
                                value={result.score}
                                range={gradeRange(averages[subj.id])}
                                unit="点"
                                size="inline"
                                labels={{
                                  "critical-low": "赤点",
                                  low: "要観察",
                                  normal: "基準到達",
                                }}
                              />
                            )}
                            <div className="flex items-center gap-1">
                              <span
                                className="text-[11px] text-muted-foreground"
                                title="評定（5段階）"
                              >
                                評定{" "}
                                <span className="font-semibold text-foreground tabular-nums">
                                  {result.hyotei ?? "—"}
                                </span>
                              </span>
                              {result.confirmed && (
                                <IconLock className="h-3 w-3 text-muted-foreground" aria-label="確定済み" />
                              )}
                            </div>
                            <Button
                              variant="ghost"
                              size="sm"
                              className="h-6 px-2 text-[11px]"
                              onClick={() => setEditing({ studentId: student.id, subject: subj.id })}
                            >
                              <IconPencil className="mr-1 h-3 w-3" aria-hidden />
                              {result.confirmed ? "確認" : "入力"}
                            </Button>
                          </div>
                        </td>
                      )
                    })}
                    <td className="px-3 py-2 text-center align-middle">
                      {nFail > 0 ? (
                        <Badge variant="destructive">{nFail}</Badge>
                      ) : (
                        <span className="text-xs text-muted-foreground">0</span>
                      )}
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </section>

      {/* ── 教科フォーカス：分布 + 観点別 ── */}
      <section aria-labelledby="subject-heading" className="space-y-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <h2 id="subject-heading" className="text-lg font-semibold">
            教科別の詳細
          </h2>
          <label className="flex items-center gap-2 text-sm">
            <span className="text-muted-foreground">対象教科</span>
            <Select
              value={focusSubject}
              onChange={(e) => setFocusSubject(e.target.value as SubjectId)}
              className="w-36"
              aria-label="詳細を表示する教科"
            >
              {SUBJECTS.map((s) => (
                <option key={s.id} value={s.id}>
                  {s.name}
                </option>
              ))}
            </Select>
          </label>
        </div>

        <Tabs defaultValue="distribution" className="w-full">
          <TabsList>
            <TabsTrigger value="distribution">成績分布</TabsTrigger>
            <TabsTrigger value="standard">評定 vs 基準</TabsTrigger>
            <TabsTrigger value="viewpoints">観点別評価</TabsTrigger>
          </TabsList>

          {/* 成績分布 */}
          <TabsContent value="distribution">
            <Card>
              <CardHeader>
                <CardTitle as="h3" className="text-base">
                  {SUBJECTS.find((s) => s.id === focusSubject)?.name} の得点分布
                </CardTitle>
                <CardDescription>
                  採点済み {focusStats.count}名。0–29点は赤点ゾーン。
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <DistributionBar
                  segments={distribution.map((b) => ({
                    label: b.label,
                    value: b.count,
                    color: b.tone,
                  }))}
                  showLegend
                  formatValue={(v) => `${v}名`}
                  totalLabel="人数"
                />
                <ul className="grid grid-cols-2 gap-2 sm:grid-cols-5">
                  {distribution.map((b) => (
                    <li
                      key={b.id}
                      className="flex flex-col rounded-md border bg-muted/20 px-3 py-2 text-center"
                    >
                      <span className="text-xs text-muted-foreground">{b.label}</span>
                      <span className="text-xl font-bold tabular-nums">{b.count}</span>
                      <span className="text-[11px] text-muted-foreground">名</span>
                    </li>
                  ))}
                </ul>
              </CardContent>
            </Card>
          </TabsContent>

          {/* 評定 vs 基準（Meter で「点数 / 100、合格基準=target」を表現） */}
          <TabsContent value="standard">
            <Card>
              <CardHeader>
                <CardTitle as="h3" className="text-base">
                  {SUBJECTS.find((s) => s.id === focusSubject)?.name} — 得点 vs 合格基準・平均
                </CardTitle>
                <CardDescription>
                  バーの縦線が合格基準点（{PASSING_SCORE}点）。基準未満は赤、平均（
                  {focusStats.average}点）未満は要観察として扱います。
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {students.map((student) => {
                  const result = student.results[focusSubject]
                  const status = scoreStatus(result.score, focusStats.average)
                  return (
                    <div
                      key={student.id}
                      className="grid grid-cols-[8rem_1fr_auto] items-center gap-3"
                    >
                      <span className="truncate text-sm">
                        {student.no}. {student.name}
                      </span>
                      {result.score == null ? (
                        <span className="text-xs text-muted-foreground">未入力</span>
                      ) : (
                        <Meter
                          value={result.score}
                          max={100}
                          target={PASSING_SCORE}
                          direction="higher-is-better"
                          tone={status === "failing" ? "destructive" : status === "watch" ? "warning" : "success"}
                          unit="点"
                          size="inline"
                          label={`${student.name} の${SUBJECTS.find((s) => s.id === focusSubject)?.name}`}
                        />
                      )}
                      {status === "failing" ? (
                        <Badge variant="destructive">赤点</Badge>
                      ) : status === "watch" ? (
                        <Badge variant="warning">要観察</Badge>
                      ) : status === "unentered" ? (
                        <Badge variant="outline">未</Badge>
                      ) : (
                        <Badge variant="success">良</Badge>
                      )}
                    </div>
                  )
                })}
              </CardContent>
            </Card>
          </TabsContent>

          {/* 観点別評価 */}
          <TabsContent value="viewpoints">
            <Card>
              <CardHeader>
                <CardTitle as="h3" className="text-base">
                  {SUBJECTS.find((s) => s.id === focusSubject)?.name} — 観点別評価（3観点）
                </CardTitle>
                <CardDescription>
                  知識・技能 / 思考・判断・表現 / 主体的に取り組む態度 を A・B・C で評価し、評定（1〜5）に集約します。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>生徒</TableHead>
                      {VIEWPOINTS.map((v) => (
                        <TableHead key={v.id} className="text-center">
                          {v.name}
                        </TableHead>
                      ))}
                      <TableHead className="text-center">評定</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {students.map((student) => {
                      const result = student.results[focusSubject]
                      return (
                        <TableRow key={student.id}>
                          <TableCell className="whitespace-nowrap">
                            {student.no}. {student.name}
                          </TableCell>
                          {VIEWPOINTS.map((v) => (
                            <TableCell key={v.id} className="text-center">
                              <ViewpointBadge grade={result.viewpoints[v.id]} />
                            </TableCell>
                          ))}
                          <TableCell className="text-center">
                            <span className="text-base font-bold tabular-nums">
                              {result.hyotei ?? "—"}
                            </span>
                            {result.confirmed && (
                              <IconLock className="ml-1 inline h-3 w-3 text-muted-foreground" aria-label="確定済み" />
                            )}
                          </TableCell>
                        </TableRow>
                      )
                    })}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </section>

      {/* ── 評定入力・確定シート ── */}
      <Sheet open={editing != null} onOpenChange={(open) => !open && setEditing(null)}>
        <SheetContent side="right" className="w-full overflow-y-auto sm:max-w-md">
          {editingStudent && editing && (
            <EditPanel
              student={editingStudent}
              subject={editing.subject}
              classAverage={averages[editing.subject]}
              onChange={(patch) => updateResult(editingStudent.id, editing.subject, patch)}
              onClose={() => setEditing(null)}
            />
          )}
        </SheetContent>
      </Sheet>

      {/* ── 個人通知表プレビュー ── */}
      <Sheet open={reportStudentId != null} onOpenChange={(open) => !open && setReportStudentId(null)}>
        <SheetContent side="right" className="w-full overflow-y-auto sm:max-w-lg">
          {reportStudent && (
            <ReportCard
              student={reportStudent}
              averages={averages}
              onEdit={(subject) => {
                setReportStudentId(null)
                setEditing({ studentId: reportStudent.id, subject })
              }}
            />
          )}
        </SheetContent>
      </Sheet>
    </div>
  )
}

// ─────────────────────────────────────────────────────────
// 評定入力・確定パネル
// ─────────────────────────────────────────────────────────
function EditPanel({
  student,
  subject,
  classAverage,
  onChange,
  onClose,
}: {
  student: Student
  subject: SubjectId
  classAverage: number
  onChange: (patch: Partial<Student["results"][SubjectId]>) => void
  onClose: () => void
}) {
  const result = student.results[subject]
  const subjectName = SUBJECTS.find((s) => s.id === subject)?.name
  const status = scoreStatus(result.score, classAverage)
  const suggested = suggestHyotei(result.viewpoints)

  return (
    <>
      <SheetHeader>
        <SheetTitle>
          評定入力 — {student.name} / {subjectName}
        </SheetTitle>
        <SheetDescription>
          素点・観点別評価を入力し、評定を確定すると通知表に反映されます。確定後はロックされます。
        </SheetDescription>
      </SheetHeader>

      <div className="mt-6 space-y-6">
        {result.confirmed && (
          <div className="flex items-center gap-2 rounded-md border border-success-border bg-success-subtle px-3 py-2 text-sm text-success-subtle-foreground">
            <IconCheck className="h-4 w-4" aria-hidden />
            この評定は確定済みです。修正するには確定を解除してください。
          </div>
        )}

        {/* 素点 */}
        <div className="space-y-1.5">
          <label htmlFor="score-input" className="text-sm font-medium">
            素点（100点満点）
          </label>
          <div className="flex items-center gap-3">
            <input
              id="score-input"
              type="number"
              min={0}
              max={100}
              disabled={result.confirmed}
              value={result.score ?? ""}
              onChange={(e) =>
                onChange({ score: e.target.value === "" ? null : Number(e.target.value) })
              }
              className="h-9 w-24 rounded-lg border border-input bg-transparent px-3 text-sm tabular-nums focus:outline-none focus:ring-1 focus:ring-ring disabled:bg-muted disabled:opacity-50"
            />
            {result.score != null && (
              <ReferenceValue
                value={result.score}
                range={gradeRange(classAverage)}
                unit="点"
                showLabel
                showRange
                rangeLabel="合格基準"
                labels={{ "critical-low": "赤点", low: "要観察", normal: "基準到達" }}
              />
            )}
          </div>
          {status === "failing" && (
            <p className="text-xs text-destructive">
              合格基準点（{PASSING_SCORE}点）未満です。赤点として通知表に記録されます。
            </p>
          )}
        </div>

        {/* 観点別評価 */}
        <fieldset className="space-y-3" disabled={result.confirmed}>
          <legend className="text-sm font-medium">観点別評価</legend>
          {VIEWPOINTS.map((v) => (
            <div key={v.id} className="flex items-center justify-between gap-3">
              <span className="text-sm text-muted-foreground">{v.name}</span>
              <div role="radiogroup" aria-label={v.name} className="inline-flex gap-1">
                {(["A", "B", "C"] as ViewpointGrade[]).map((g) => {
                  const selected = result.viewpoints[v.id] === g
                  return (
                    <Button
                      key={g}
                      type="button"
                      role="radio"
                      aria-checked={selected}
                      variant={selected ? "default" : "outline"}
                      size="sm"
                      className="h-8 w-8 p-0"
                      disabled={result.confirmed}
                      onClick={() => {
                        const nextVp = { ...result.viewpoints, [v.id]: g } as Record<ViewpointId, ViewpointGrade>
                        onChange({ viewpoints: nextVp, hyotei: suggestHyotei(nextVp) })
                      }}
                    >
                      {g}
                    </Button>
                  )
                })}
              </div>
            </div>
          ))}
        </fieldset>

        {/* 評定（自動提案 + 手動上書き） */}
        <div className="space-y-1.5">
          <label htmlFor="hyotei-select" className="text-sm font-medium">
            評定（5段階）
          </label>
          <div className="flex items-center gap-3">
            <Select
              id="hyotei-select"
              value={String(result.hyotei ?? suggested)}
              disabled={result.confirmed}
              onChange={(e) => onChange({ hyotei: Number(e.target.value) as Hyotei })}
              className="w-24"
            >
              {[5, 4, 3, 2, 1].map((n) => (
                <option key={n} value={n}>
                  {n}
                </option>
              ))}
            </Select>
            <span className="text-xs text-muted-foreground">
              観点からの提案: <strong className="text-foreground">{suggested}</strong>
              {result.hyotei !== suggested && (
                <Badge variant="warning" className="ml-2">
                  手動上書き
                </Badge>
              )}
            </span>
          </div>
        </div>
      </div>

      <SheetFooter className="mt-8">
        <Button variant="outline" onClick={onClose}>
          閉じる
        </Button>
        {result.confirmed ? (
          <Button variant="outline" onClick={() => onChange({ confirmed: false })}>
            <IconLock className="mr-1.5 h-4 w-4" aria-hidden />
            確定を解除
          </Button>
        ) : (
          <AlertDialog>
            <AlertDialogTrigger asChild>
              <Button disabled={result.score == null}>評定を確定</Button>
            </AlertDialogTrigger>
            <AlertDialogContent>
              <AlertDialogHeader>
                <AlertDialogTitle>評定を確定しますか？</AlertDialogTitle>
                <AlertDialogDescription>
                  {student.name} の {subjectName} の評定（{result.hyotei}）を確定します。
                  確定後は通知表に反映され、ロックされます。修正するには確定解除が必要です。
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>キャンセル</AlertDialogCancel>
                <AlertDialogAction onClick={() => onChange({ confirmed: true })}>
                  確定する
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>
        )}
      </SheetFooter>
    </>
  )
}

// ─────────────────────────────────────────────────────────
// 個人通知表プレビュー
// ─────────────────────────────────────────────────────────
function ReportCard({
  student,
  averages,
  onEdit,
}: {
  student: Student
  averages: Record<SubjectId, number>
  onEdit: (subject: SubjectId) => void
}) {
  const nFail = failingCount(student)
  const hyoteiSum = SUBJECTS.reduce((sum, s) => sum + (student.results[s.id].hyotei ?? 0), 0)
  const confirmedCount = SUBJECTS.filter((s) => student.results[s.id].confirmed).length

  return (
    <>
      <SheetHeader>
        <SheetTitle>通知表プレビュー — {student.name}</SheetTitle>
        <SheetDescription>
          {CLASS_LABEL} 出席番号 {student.no} / {TERM_LABEL}
        </SheetDescription>
      </SheetHeader>

      <div className="mt-6 space-y-5">
        <div className="grid grid-cols-3 gap-3">
          <Statistic label="評定合計" value={`${hyoteiSum}`} hint="25点満点" />
          <Statistic
            label="赤点"
            value={`${nFail}教科`}
            tone={nFail > 0 ? "negative" : "neutral"}
            trend={nFail > 0 ? "down" : "flat"}
          />
          <Statistic label="確定" value={`${confirmedCount}/${SUBJECTS.length}`} hint="教科" />
        </div>

        {nFail > 0 && (
          <div className="flex items-start gap-2 rounded-md border border-destructive-border bg-destructive-subtle px-3 py-2 text-sm text-destructive-subtle-foreground">
            <IconAlertTriangle className="mt-0.5 h-4 w-4 shrink-0" aria-hidden />
            <span>
              {nFail}教科で赤点があります。補習・再評価の対象です。
            </span>
          </div>
        )}

        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>教科</TableHead>
              <TableHead className="text-right">素点</TableHead>
              <TableHead className="text-center">評定</TableHead>
              <TableHead className="text-center">状態</TableHead>
              <TableHead className="text-right">操作</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {SUBJECTS.map((subj) => {
              const result = student.results[subj.id]
              const status = scoreStatus(result.score, averages[subj.id])
              return (
                <TableRow key={subj.id}>
                  <TableCell className="font-medium">{subj.name}</TableCell>
                  <TableCell className="text-right">
                    {result.score == null ? (
                      <span className="text-xs text-muted-foreground">未入力</span>
                    ) : (
                      <ReferenceValue
                        value={result.score}
                        range={gradeRange(averages[subj.id])}
                        unit="点"
                        size="inline"
                        hideFlag
                        labels={{ "critical-low": "赤点", low: "要観察", normal: "基準到達" }}
                      />
                    )}
                  </TableCell>
                  <TableCell className="text-center">
                    <span className="font-bold tabular-nums">{result.hyotei ?? "—"}</span>
                    {result.confirmed && (
                      <IconLock className="ml-1 inline h-3 w-3 text-muted-foreground" aria-label="確定済み" />
                    )}
                  </TableCell>
                  <TableCell className="text-center">
                    {status === "failing" ? (
                      <Badge variant="destructive">赤点</Badge>
                    ) : status === "watch" ? (
                      <Badge variant="warning">要観察</Badge>
                    ) : status === "unentered" ? (
                      <Badge variant="outline">未</Badge>
                    ) : (
                      <Badge variant="success">良</Badge>
                    )}
                  </TableCell>
                  <TableCell className="text-right">
                    <Button variant="ghost" size="sm" className="h-7" onClick={() => onEdit(subj.id)}>
                      <IconPencil className="mr-1 h-3 w-3" aria-hidden />
                      編集
                    </Button>
                  </TableCell>
                </TableRow>
              )
            })}
          </TableBody>
        </Table>

        <p className="text-xs text-muted-foreground">
          <IconEye className="mr-1 inline h-3 w-3" aria-hidden />
          このプレビューは確定済みの評定を保護者向け通知表として出力する前の確認用です。
        </p>
      </div>
    </>
  )
}
